package org.joda.time.format;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.joda.time.format.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.joda.time.format.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.joda.time.LocalDate;
import org.joda.time.chrono.ISOChronology;
import static org.junit.Assert.assertEquals;

public class StepDefs {

    private DateTimeFormatter formatter;
    private LocalDate result;
    private String dateString;

    @Given("the date time formatter pattern is {string}")
    public void the_date_time_formatter_pattern_is(String pattern) {
        formatter = DateTimeFormat.forPattern(pattern).withChronology(ISOChronology.getInstanceUTC());
    }

    @Given("the chronology is UTC")
    public void the_chronology_is_utc() {
        // The formatter is already configured with UTC chronology
    }

    @When("the string {string} is parsed to a LocalDate")
    public void the_string_is_parsed_to_a_LocalDate(String dateStr) {
        this.dateString = dateStr;
        try {
            result = formatter.parseLocalDate(dateStr);
        } catch (Exception e) {
            // Store the exception for later assertion if needed
            throw new RuntimeException(e);
        }
    }

    @Then("the resulting LocalDate should be {string}")
    public void the_resulting_LocalDate_should_be(String expectedDate) {
        LocalDate expected = LocalDate.parse(expectedDate);
        assertEquals("Parsed date should match expected date", expected, result);
    }
}

